%% Camera-to-Projector Coordinate Mapping
% Loads calibration points generated by mapping.m, fits a geometric
% transform from camera pixel coordinates to projector (DMD) coordinates,
% evaluates reprojection error, and saves the transform for reuse.

clear; clc; close all;

%% --- Parameters -----------------------------------------------------------

INPUT_FILE = 'calibration_points.mat';
OUTPUT_FILE = 'camera_to_projector_transform.mat';

% Supported by fitgeotrans: 'affine', 'projective', 'polynomial', 'pwl', 'lwm'
% For projector-camera mapping, 'projective' is usually a good first choice.
TFORM_TYPE = 'projective';

% Minimum points required by transform type
switch lower(TFORM_TYPE)
    case 'affine'
        min_points = 3;
    case 'projective'
        min_points = 4;
    otherwise
        min_points = 6; % conservative default for higher-order models
end

%% --- Step 1: Load calibration data ---------------------------------------

fprintf('Loading calibration data from %s\n', INPUT_FILE);
S = load(INPUT_FILE);

required_vars = {'camera_coords_v', 'dmd_coords_v'};
for i = 1:numel(required_vars)
    if ~isfield(S, required_vars{i})
        error('Missing variable "%s" in %s.', required_vars{i}, INPUT_FILE);
    end
end

camera_pts = double(S.camera_coords_v);
dmd_pts = double(S.dmd_coords_v);

if size(camera_pts, 2) ~= 2 || size(dmd_pts, 2) ~= 2
    error('camera_coords_v and dmd_coords_v must both be [N x 2].');
end

if size(camera_pts, 1) ~= size(dmd_pts, 1)
    error('camera_coords_v and dmd_coords_v must have the same number of rows.');
end

n = size(camera_pts, 1);
fprintf('Loaded %d matched point pairs.\n', n);

if n < min_points
    error('Need at least %d point pairs for "%s" transform (found %d).', min_points, TFORM_TYPE, n);
end

%% --- Step 2: Fit camera -> projector transform ---------------------------

fprintf('Fitting %s transform (camera -> projector)...\n', TFORM_TYPE);

% moving points = camera; fixed points = projector (DMD)
tform_cam_to_dmd = fitgeotrans(camera_pts, dmd_pts, TFORM_TYPE);

%% --- Step 3: Evaluate reprojection error ---------------------------------

[dmd_pred_x, dmd_pred_y] = transformPointsForward( ...
    tform_cam_to_dmd, camera_pts(:,1), camera_pts(:,2));

dmd_pred = [dmd_pred_x, dmd_pred_y];
residual = dmd_pred - dmd_pts;
per_point_error = hypot(residual(:,1), residual(:,2));
rmse = sqrt(mean(per_point_error.^2));

fprintf('Reprojection error in DMD pixels:\n');
fprintf('  Mean  : %.3f px\n', mean(per_point_error));
fprintf('  Median: %.3f px\n', median(per_point_error));
fprintf('  Max   : %.3f px\n', max(per_point_error));
fprintf('  RMSE  : %.3f px\n', rmse);

%% --- Step 4: Visual sanity checks ----------------------------------------

figure('Name', 'Projector Fit: Ground Truth vs Predicted');
subplot(1,2,1);
scatter(dmd_pts(:,1), dmd_pts(:,2), 8, 'b', 'filled');
title('Ground truth DMD points');
xlabel('DMD X (px)'); ylabel('DMD Y (px)');
set(gca, 'YDir', 'reverse'); axis equal tight; grid on;

subplot(1,2,2);
scatter(dmd_pred(:,1), dmd_pred(:,2), 8, 'r', 'filled');
title('Predicted DMD points (from camera)');
xlabel('DMD X (px)'); ylabel('DMD Y (px)');
set(gca, 'YDir', 'reverse'); axis equal tight; grid on;

figure('Name', 'Per-point Reprojection Error (DMD px)');
scatter(camera_pts(:,1), camera_pts(:,2), 20, per_point_error, 'filled');
colormap(hot); colorbar;
title('Camera points colored by reprojection error');
xlabel('Camera X (px)'); ylabel('Camera Y (px)');
set(gca, 'YDir', 'reverse'); axis equal tight; grid on;

%% --- Step 5: Save transform ----------------------------------------------

save(OUTPUT_FILE, ...
    'tform_cam_to_dmd', ...
    'TFORM_TYPE', ...
    'camera_pts', ...
    'dmd_pts', ...
    'dmd_pred', ...
    'per_point_error', ...
    'rmse');

fprintf('\nSaved transform to %s\n', OUTPUT_FILE);
fprintf('Use this helper to map camera -> projector coordinates:\n');
fprintf('  [px, py] = transformPointsForward(tform_cam_to_dmd, cx, cy);\n');

%% --- Step 6: Export transform matrix for C++ integration ------------------
% Export the 3x3 homography matrix as CSV for easy loading in C++

H_matrix = tform_cam_to_dmd.T';  % MATLAB fitgeotrans uses row vectors; transpose for column-vector convention
csvwrite('camera_to_projector_matrix.csv', H_matrix);

fprintf('\nAlso exported 3x3 homography matrix to camera_to_projector_matrix.csv\n');
fprintf('C++ usage:\n');
fprintf('  1. Load camera_to_projector_matrix.csv at startup\n');
fprintf('  2. Apply homography: [p_tilde_x, p_tilde_y, w_tilde] = H * [cx, cy, 1]^T\n');
fprintf('  3. Normalize: px = p_tilde_x / w_tilde, py = p_tilde_y / w_tilde\n');
